code = """import json
import re
import pandas as pd

# Load results from previous tool calls
# var_call_3WGta1VKkaFZHFqxh4mdv45i may be a filepath (string) containing the large JSON result
books_path = var_call_3WGta1VKkaFZHFqxh4mdv45i
if isinstance(books_path, str):
    with open(books_path, 'r', encoding='utf-8') as f:
        books = json.load(f)
else:
    books = books_path

reviews = var_call_4ehSg8tMU7LuWnnE89grHxd8

# Convert to DataFrame
df_books = pd.DataFrame(books)
df_reviews = pd.DataFrame(reviews)

# Extract numeric id from book_id and purchase_id
def extract_num(s):
    if s is None:
        return None
    m = re.search(r"(\d+)", str(s))
    return m.group(1) if m else None

if 'book_id' in df_books.columns:
    df_books['id_num'] = df_books['book_id'].apply(extract_num)
else:
    df_books['id_num'] = df_books['title'].apply(lambda x: None)

if 'purchase_id' in df_reviews.columns:
    df_reviews['id_num'] = df_reviews['purchase_id'].apply(extract_num)
else:
    df_reviews['id_num'] = None

# Keep only reviews with avg_rating == 5.0 (they already are) and convert cnt to int
df_reviews['avg_rating'] = df_reviews['avg_rating'].astype(float)
df_reviews['cnt'] = df_reviews['cnt'].astype(int)

# Filter books that are English-language using details or categories
def is_english(details, categories):
    txt = ''
    if isinstance(details, str):
        txt += details + ' '
    if isinstance(categories, str):
        txt += categories
    return bool(re.search(r"\benglish\b", txt, flags=re.IGNORECASE))

df_books['is_english'] = df_books.apply(lambda r: is_english(r.get('details',''), r.get('categories','')), axis=1)

# Merge on id_num
df_merged = pd.merge(df_books, df_reviews[['id_num','avg_rating','cnt']], on='id_num', how='inner')

# Keep only English
df_final = df_merged[df_merged['is_english'] == True].copy()

# Prepare output records
output = []
for _, row in df_final.iterrows():
    # parse author field if it's JSON-like
    author = row.get('author')
    author_name = None
    if isinstance(author, str):
        a = author.strip()
        if a.lower() == 'none' or a == '':
            author_name = None
        elif a.startswith('{') or a.startswith('['):
            try:
                parsed = json.loads(a)
                if isinstance(parsed, dict):
                    author_name = parsed.get('name')
                else:
                    author_name = str(parsed)
            except Exception:
                author_name = a
        else:
            author_name = a
    else:
        author_name = author

    record = {
        'book_id': row.get('book_id'),
        'title': row.get('title'),
        'author': author_name,
        'categories': row.get('categories'),
        'details': row.get('details'),
        'avg_rating': float(row.get('avg_rating')),
        'review_count': int(row.get('cnt'))
    }
    output.append(record)

# Sort output by title
output = sorted(output, key=lambda x: (x['title'] or '').lower())

import json as _json
print("__RESULT__:")
print(_json.dumps(output))"""

